// API Service with OAuth
class APIService {
  constructor(oauth2Service, baseURL) {
    this.oauth2Service = oauth2Service;
    this.baseURL = baseURL;
  }

  async fetch(endpoint, options = {}) {
    const accessToken = await this.oauth2Service.getValidAccessToken();

    const headers = {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${accessToken}`,
      ...options.headers
    };

    const response = await fetch(`${this.baseURL}${endpoint}`, {
      ...options,
      headers
    });

    if (response.status === 401) {
      try {
        await this.oauth2Service.refreshAccessToken();
        const newAccessToken = this.oauth2Service.getAccessToken();
        headers['Authorization'] = `Bearer ${newAccessToken}`;

        return await fetch(`${this.baseURL}${endpoint}`, {
          ...options,
          headers
        });
      } catch (error) {
        this.oauth2Service.logout();
        throw new Error('Authentication failed');
      }
    }

    return response;
  }

  async get(endpoint) {
    const response = await this.fetch(endpoint, { method: 'GET' });
    return response.json();
  }

  async post(endpoint, data) {
    const response = await this.fetch(endpoint, {
      method: 'POST',
      body: JSON.stringify(data)
    });
    return response.json();
  }

  async put(endpoint, data) {
    const response = await this.fetch(endpoint, {
      method: 'PUT',
      body: JSON.stringify(data)
    });
    return response.json();
  }

  async delete(endpoint) {
    const response = await this.fetch(endpoint, { method: 'DELETE' });
    return response.json();
  }
}

